import { Search } from 'lucide-react';

import React, { useState } from 'react';
import { Doctor } from '../types';
import { X, Calendar, Clock, CheckCircle, ShieldCheck } from 'lucide-react';
import { Button } from './Button';

interface BookingModalProps {
  doctor: Doctor | null;
  onClose: () => void;
  onConfirm: () => void;
}

export const BookingModal: React.FC<BookingModalProps> = ({ doctor, onClose, onConfirm }) => {
  const [selectedDate, setSelectedDate] = useState<string>('');
  const [selectedSlot, setSelectedSlot] = useState<string>('');
  const [step, setStep] = useState(1);

  if (!doctor) return null;

  const dates = [
    { label: 'Today', value: '2023-10-27' },
    { label: 'Tomorrow', value: '2023-10-28' },
    { label: 'Mon, 29 Oct', value: '2023-10-29' },
  ];

  const handleBook = () => {
    if (selectedDate && selectedSlot) {
      setStep(2);
      setTimeout(() => {
        onConfirm();
      }, 1500);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] overflow-y-auto" aria-labelledby="modal-title" role="dialog" aria-modal="true">
      <div className="flex items-center justify-center min-h-screen px-4 py-6">

        {/* Overlay */}
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md transition-opacity" aria-hidden="true" onClick={onClose}></div>

        {/* Modal Panel */}
        <div className="relative bg-white rounded-[32px] text-left overflow-hidden shadow-2xl shadow-brand-900/20 transform transition-all sm:max-w-xl w-full border border-white">

          {step === 1 ? (
            <div className="p-8">
              {/* Header */}
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-2xl font-black text-slate-900">Book Appointment</h3>
                  <div className="flex items-center gap-1.5 text-brand-600 font-bold text-xs mt-1 uppercase tracking-widest">
                    <ShieldCheck className="w-3.5 h-3.5" />
                    Verified Specialist
                  </div>
                </div>
                <button onClick={onClose} className="bg-slate-100 hover:bg-slate-200 text-slate-500 rounded-full p-2 transition-colors">
                  <X className="h-6 w-6" />
                </button>
              </div>

              {/* Progress Bar */}
              <div className="flex gap-2 mb-8">
                 <div className="h-2 flex-1 rounded-full bg-brand-600"></div>
                 <div className="h-2 flex-1 rounded-full bg-slate-100"></div>
                 <div className="h-2 flex-1 rounded-full bg-slate-100"></div>
              </div>

              {/* Doctor Card Snippet */}
              <div className="flex items-center gap-5 p-5 bg-slate-50 rounded-2xl border border-slate-100 mb-8">
                <img src={doctor.image} alt="" className="h-20 w-20 rounded-2xl object-cover shadow-sm border-2 border-white" />
                <div>
                  <h4 className="font-bold text-slate-900 text-xl">{doctor.name}</h4>
                  <p className="text-sm text-slate-500 font-medium">{doctor.specialty}</p>
                  <p className="text-brand-600 text-xs font-black mt-1 uppercase tracking-tighter">Consultation: ${doctor.fee}</p>
                </div>
              </div>

              {/* Selection Sections */}
              <div className="space-y-8">
                <div>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <Calendar className="w-4 h-4 text-brand-500" /> Select Date
                  </h4>
                  <div className="flex gap-3 overflow-x-auto pb-2">
                    {dates.map((d) => (
                      <button
                        key={d.value}
                        onClick={() => setSelectedDate(d.value)}
                        className={`px-6 py-4 rounded-2xl text-sm font-bold whitespace-nowrap transition-all border-2 ${
                          selectedDate === d.value 
                            ? 'bg-brand-600 text-white border-brand-600 shadow-xl shadow-brand-100 scale-[1.02]' 
                            : 'bg-white text-slate-700 border-slate-100 hover:border-brand-200'
                        }`}
                      >
                        {d.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <Clock className="w-4 h-4 text-brand-500" /> Choose Time
                  </h4>
                  <div className="grid grid-cols-3 gap-3">
                    {doctor.availableSlots.map((slot) => (
                      <button
                        key={slot}
                        onClick={() => setSelectedSlot(slot)}
                        className={`px-4 py-4 rounded-2xl text-sm font-bold transition-all border-2 ${
                          selectedSlot === slot 
                            ? 'bg-brand-600 text-white border-brand-600 shadow-xl shadow-brand-100' 
                            : 'bg-white text-slate-700 border-slate-100 hover:border-brand-200'
                        }`}
                      >
                        {slot}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex flex-col sm:flex-row gap-4 mt-10">
                <Button 
                  onClick={handleBook} 
                  disabled={!selectedDate || !selectedSlot}
                  className="flex-1 py-4 text-lg font-black bg-brand-600 hover:bg-brand-700 shadow-xl shadow-brand-100"
                >
                  CONFIRM BOOKING
                </Button>
                <Button 
                  variant="outline"
                  onClick={onClose} 
                  className="px-8 py-4 font-bold border-2 border-slate-100 text-slate-500 hover:bg-slate-50"
                >
                  Close
                </Button>
              </div>
            </div>
          ) : (
            <div className="p-16 text-center">
              <div className="mx-auto flex items-center justify-center h-24 w-24 rounded-full bg-emerald-100 mb-8 animate-bounce">
                <CheckCircle className="h-12 w-12 text-emerald-600" />
              </div>
              <h3 className="text-3xl font-black text-slate-900 mb-4">Confirmed!</h3>
              <p className="text-slate-500 text-lg leading-relaxed">
                You're all set. We've sent an SMS confirmation with the details for your appointment with <strong>Dr. {doctor.name.split(' ')[1]}</strong>.
              </p>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { SpecialtyCards } from './components/SpecialtyCards';
import { DoctorList } from './components/DoctorList';
import { BookingModal } from './components/BookingModal';
import { SignIn } from './components/SignIn';
import { SignUp } from './components/SignUp';
import { SignUpPatient } from './components/SignUpPatient';
import { SignUpSpecialist } from './components/SignUpSpecialist';
import { SignUpClinic } from './components/SignUpClinic';
import { AskExpert } from './components/AskExpert';
import { DOCTORS as MOCK_DOCTORS, INSURANCE_PROVIDERS } from './constants';
import { Doctor, FilterState, Page } from './types';
import { Button } from './components/Button';
import { 
  ArrowLeft, 
  Search,
  CalendarCheck, 
  Clock, 
  ThumbsUp,
  Check,
  Stethoscope,
  Facebook,
  Twitter,
  Instagram,
  Linkedin,
  ShieldCheck
} from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [filters, setFilters] = useState<FilterState>({ location: '', specialty: '', query: '', insurance: '' });
  const [selectedDoctor, setSelectedDoctor] = useState<Doctor | null>(null);
  const [isBookingModalOpen, setIsBookingModalOpen] = useState(false);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchDoctors = async () => {
      try {
        const response = await fetch('http://localhost:3000/api/doctors');
        if (!response.ok) throw new Error('Backend not available');
        const data = await response.json();
        setDoctors(data);
      } catch (error) {
        setDoctors(MOCK_DOCTORS);
      } finally {
        setIsLoading(false);
      }
    };
    fetchDoctors();
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

  const handleSearch = (newFilters: FilterState) => {
    setFilters(newFilters);
    handleNavigate(Page.SEARCH);
  };

  const handleSelectSpecialty = (specialty: string) => {
    setFilters({ location: '', specialty, query: '', insurance: '' });
    handleNavigate(Page.SEARCH);
  };

  const handleBookClick = (doctor: Doctor) => {
    setSelectedDoctor(doctor);
    setIsBookingModalOpen(true);
  };

  const handleBookingConfirm = () => {
    setIsBookingModalOpen(false);
    handleNavigate(Page.APPOINTMENT_SUCCESS);
  };

  const filteredDoctors = useMemo(() => {
    return doctors.filter(doc => {
      const matchLoc = filters.location ? doc.location.toLowerCase().includes(filters.location.toLowerCase()) : true;
      const matchSpec = filters.specialty ? doc.specialty === filters.specialty : true;
      const matchQuery = filters.query 
        ? (doc.name.toLowerCase().includes(filters.query.toLowerCase()) || 
           doc.specialty.toLowerCase().includes(filters.query.toLowerCase()))
        : true;
      const matchInsurance = filters.insurance 
        ? doc.insuranceAccepted.includes(filters.insurance)
        : true;
      return matchLoc && matchSpec && matchQuery && matchInsurance;
    });
  }, [filters, doctors]);

  return (
