interface BookingModalProps {
  doctor: Doctor | null;
  onClose: () => void;
  onConfirm: () => void;
}

export const BookingModal: React.FC<BookingModalProps> = ({ doctor, onClose, onConfirm }) => {
  const [selectedDate, setSelectedDate] = useState<string>('');
  const [selectedSlot, setSelectedSlot] = useState<string>('');
  const [step, setStep] = useState(1);

  if (!doctor) return null;

  const dates = [
    { label: 'Today', value: '2025-05-15' },
    { label: 'Tomorrow', value: '2025-05-16' },
    { label: 'Mon, 17 May', value: '2025-05-17' },
    { label: 'Tue, 18 May', value: '2025-05-18' },
  ];

  const handleBook = () => {
    if (selectedDate && selectedSlot) {
      setStep(4); // Moving to success step
      setTimeout(() => {
        onConfirm();
      }, 3000);
    }
  };

  const steps = [
    { id: 1, label: 'Specialist' },
    { id: 2, label: 'Date & Time' },
    { id: 3, label: 'Confirm' },
    { id: 4, label: 'Done' }
  ];

  return (
    <div className="fixed inset-0 z-[100] overflow-y-auto" aria-labelledby="modal-title" role="dialog" aria-modal="true">
      <div className="flex items-center justify-center min-h-screen px-4 py-8">

        {/* Deep Overlay */}
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl transition-opacity" aria-hidden="true" onClick={onClose}></div>

        {/* Modal Panel */}
        <div className="relative bg-white rounded-[48px] text-left overflow-hidden shadow-[0_32px_120px_-20px_rgba(0,0,0,0.5)] transform transition-all sm:max-w-2xl w-full border border-slate-100">

          {step < 4 ? (
            <div className="p-8 md:p-12">
              {/* Top Navigation */}
              <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">Secure Booking</h3>
                  <div className="flex items-center gap-1.5 text-brand-600 font-black text-[10px] mt-1 uppercase tracking-[0.2em]">
                    <ShieldCheck className="w-4 h-4" />
                    Certified Clinic Professional
                  </div>
                </div>
                <button onClick={onClose} className="bg-slate-50 hover:bg-slate-100 text-slate-500 rounded-full p-3 transition-colors">
                  <X className="h-6 w-6" />
                </button>
              </div>

              {/* Progress Stepper */}
              <div className="flex items-center justify-between mb-12 relative px-4">
                 <div className="absolute top-5 left-8 right-8 h-0.5 bg-slate-100 z-0"></div>
                 <div className="absolute top-5 left-8 right-8 h-0.5 bg-brand-600 z-0 transition-all duration-500" style={{ width: `${(step / 3) * 100}%` }}></div>
                 {steps.map((s) => (
                   <div key={s.id} className="relative z-10 flex flex-col items-center">
                     <div className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-sm transition-all duration-300 border-4 ${
                       step >= s.id ? 'bg-brand-600 text-white border-brand-100' : 'bg-white text-slate-300 border-slate-50'
                     }`}>
                       {step > s.id ? <CheckCircle className="w-6 h-6" /> : s.id}
                     </div>
                     <span className={`text-[10px] font-black uppercase tracking-tighter mt-3 ${step >= s.id ? 'text-brand-600' : 'text-slate-300'}`}>
                       {s.label}
                     </span>
                   </div>
                 ))}
              </div>

              {/* Simple Doctor Card */}
              <div className="flex items-center gap-6 p-6 bg-brand-50/50 rounded-[32px] border border-brand-100/50 mb-10">
                <img src={doctor.image} alt="" className="h-24 w-24 rounded-3xl object-cover shadow-lg border-4 border-white" />
                <div>
                  <h4 className="font-black text-slate-900 text-2xl">{doctor.name}</h4>
                  <p className="text-sm text-brand-600 font-bold uppercase tracking-widest">{doctor.specialty}</p>
                  <div className="flex items-center gap-2 mt-2 text-slate-500 font-bold text-xs">
                    {/* Fixed missing MapPin error */}
                    <MapPin className="w-3.5 h-3.5" />
                    {doctor.location}
                  </div>
                </div>
              </div>

              {/* Step View Switcher */}
              <div className="space-y-10">
                <div>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6 flex items-center gap-3">
                    <Calendar className="w-5 h-5 text-brand-500" /> 1. Select Preferred Date
                  </h4>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                    {dates.map((d) => (
                      <button
                        key={d.value}
                        onClick={() => { setSelectedDate(d.value); setStep(2); }}
                        className={`px-4 py-5 rounded-[20px] text-center transition-all border-2 ${
                          selectedDate === d.value 
                            ? 'bg-brand-600 text-white border-brand-600 shadow-xl shadow-brand-100 scale-[1.05]' 
                            : 'bg-white text-slate-700 border-slate-100 hover:border-brand-200'
                        }`}
                      >
                        <div className="text-[10px] uppercase font-black opacity-80 mb-1">{d.label.split(',')[0]}</div>
                        <div className="text-lg font-black leading-none">{d.label.includes(',') ? d.label.split(',')[1].trim() : ''}</div>
                        {d.label === 'Today' || d.label === 'Tomorrow' ? <div className="text-sm font-black">{d.label}</div> : null}
                      </button>
                    ))}
                  </div>
                </div>

                <div className={`${step < 2 ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'} transition-all duration-300`}>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6 flex items-center gap-3">
                    <Clock className="w-5 h-5 text-brand-500" /> 2. Choose Time Slot
                  </h4>
                  <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
                    {doctor.availableSlots.map((slot) => (
                      <button
                        key={slot}
                        onClick={() => { setSelectedSlot(slot); setStep(3); }}
                        className={`px-4 py-4 rounded-2xl text-sm font-black transition-all border-2 ${
                          selectedSlot === slot 
                            ? 'bg-brand-600 text-white border-brand-600 shadow-xl shadow-brand-100 scale-[1.05]' 
                            : 'bg-white text-slate-700 border-slate-100 hover:border-brand-200'
                        }`}
                      >
                        {slot}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {/* Footer Summary & Action */}
              <div className="mt-12 pt-10 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-6">
                 <div className="text-center sm:text-left">
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Fee</div>
                    <div className="text-3xl font-black text-slate-900 leading-none">AED {doctor.fee}</div>
                 </div>
                 <Button 
                  onClick={handleBook} 
                  disabled={step < 3}
                  className="w-full sm:w-auto px-12 py-5 text-lg font-black bg-brand-600 hover:bg-brand-700 shadow-2xl shadow-brand-200/50 rounded-[24px] flex items-center justify-center gap-3"
                >
                  CONFIRM BOOKING <ChevronRight className="w-6 h-6" />
                </Button>
              </div>
            </div>
          ) : (
            /* Success Step */
            <div className="p-16 text-center">
              <div className="mx-auto flex items-center justify-center h-28 w-28 rounded-[40px] bg-emerald-100 mb-10 shadow-2xl shadow-emerald-100 animate-bounce">
                <CheckCircle className="h-14 w-14 text-emerald-600" />
              </div>
              <h3 className="text-4xl font-black text-slate-900 mb-6 tracking-tight">Booking Confirmed!</h3>
              <p className="text-slate-500 text-xl font-medium leading-relaxed max-w-sm mx-auto mb-10">
                Great news! We've sent a <strong>WhatsApp & SMS confirmation</strong> to your mobile with all the appointment details.
              </p>

              <div className="bg-slate-50 p-6 rounded-[32px] border border-slate-100 flex items-center justify-center gap-4 text-emerald-700 font-black text-sm uppercase tracking-widest">
                 <ShieldCheck className="w-6 h-6" />
                 Clinic Notified Successfully
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

