                                <span className="group-hover:text-brand-600">Available Today</span>
                             </label>
                          </div>
                       </div>
                       <Button 
                        variant="outline" 
                        size="sm" 
                        className="w-full py-4.5 font-black text-[10px] uppercase tracking-widest border-2 border-slate-100 text-slate-400 hover:text-brand-600 hover:border-brand-600 rounded-[20px]"
                        onClick={() => setFilters({location: '', specialty: '', query: '', insurance: '', availability: 'any'})}
                       >
                         Clear All Filters
                       </Button>
                    </div>
                 </div>
              </div>

              <div className="lg:col-span-3">
                 <div className="mb-12 flex justify-between items-center bg-slate-50/50 p-6 rounded-[32px] border border-slate-100">
