                <div className="space-y-6">
                   <div className="flex justify-between items-center">
                      <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Doctor</span>
                      <span className="font-black text-slate-900 text-lg">{selectedDoctor?.name}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Specialty</span>
                      <span className="font-black text-brand-600 uppercase text-xs tracking-widest">{selectedDoctor?.specialty}</span>
