             <div className="mt-16 flex flex-col sm:flex-row gap-6 justify-center">
               <Button onClick={() => handleNavigate(Page.HOME)} className="px-12 py-5 font-black bg-slate-900 hover:bg-black shadow-2xl rounded-[24px] border-none">Go to Dashboard</Button>
